/**
 * Factory functions for timeline types.
 *
 * Each factory provides a fully-populated default value for its type.
 * Required fields must be supplied by the caller; optional fields are
 * omitted (their absence equals the documented default).
 *
 * IDs are generated by `createTimeOrderedUuid`, which mirrors the identical
 * helper in `@nodetool-ai/models` (`randomUUID` with hyphens stripped) so
 * that timeline IDs sort and index consistently alongside model IDs.
 * We replicate the helper inline to avoid pulling models (and its heavy
 * deps: drizzle, better-sqlite3) into this types-only package.
 */

import type {
  TimelineSequence,
  TimelineTrack,
  TimelineClip,
  TimelineMarker,
  ClipVersion,
  TrackEffect,
  TrackGainEffect,
  TrackEq3Effect,
  TrackFilterEffect,
  TrackCompressorEffect,
  TrackColorCorrectionEffect,
  TrackVideoBlurEffect,
  TrackSharpenEffect,
  TrackVignetteEffect,
  TrackChromaKeyEffect
} from "./types.js";

// ── Helpers ───────────────────────────────────────────────────────────

/**
 * Mirrors `createTimeOrderedUuid` from `@nodetool-ai/models`.
 * Returns a UUID v4 with hyphens stripped, matching the format used by
 * all other model IDs in the system.
 *
 * Uses the Web Crypto API (`globalThis.crypto.randomUUID`) which is
 * available in Node 19+ and all modern browsers, so this module stays
 * usable in browser builds.
 */
export function createTimeOrderedUuid(): string {
  return globalThis.crypto.randomUUID().replace(/-/g, "");
}

function nowIso(): string {
  return new Date().toISOString();
}

// ── Factories ─────────────────────────────────────────────────────────

/**
 * Create a minimal {@link TimelineMarker} with defaults applied.
 *
 * Defaults:
 * - `id`: new UUID
 * - `timeMs`: 0
 */
export function makeMarker(
  overrides: Partial<TimelineMarker> = {}
): TimelineMarker {
  return {
    id: createTimeOrderedUuid(),
    timeMs: 0,
    label: "",
    ...overrides
  };
}

/**
 * Create a minimal {@link ClipVersion} with defaults applied.
 *
 * Defaults:
 * - `id`: new UUID
 * - `createdAt`: current ISO timestamp
 * - `status`: "success"
 * - `paramOverridesSnapshot`: `{}`
 * - `dependencyHash`: `""`
 */
export function makeClipVersion(
  overrides: Partial<ClipVersion> = {}
): ClipVersion {
  return {
    id: createTimeOrderedUuid(),
    createdAt: nowIso(),
    jobId: "",
    assetId: "",
    workflowUpdatedAt: nowIso(), // placeholder — callers should supply the actual workflow updated-at timestamp
    dependencyHash: "",
    paramOverridesSnapshot: {},
    status: "success",
    ...overrides
  };
}

/**
 * Create a minimal {@link TimelineTrack} with defaults applied.
 *
 * Defaults:
 * - `id`: new UUID
 * - `type`: "video"
 * - `index`: 0
 * - `visible`: true
 * - `locked`: false
 */
export function makeTrack(
  overrides: Partial<TimelineTrack> = {}
): TimelineTrack {
  return {
    id: createTimeOrderedUuid(),
    name: "",
    type: "video",
    index: 0,
    visible: true,
    locked: false,
    ...overrides
  };
}

/**
 * Create a {@link TrackEffect} of the given type, filled with sensible
 * defaults. Each effect has `enabled: true` and a fresh `id`.
 */
export function makeTrackEffect(type: TrackEffect["type"]): TrackEffect {
  const id = createTimeOrderedUuid();
  switch (type) {
    case "gain":
      return {
        id,
        type: "gain",
        enabled: true,
        gainDb: 0
      } satisfies TrackGainEffect;
    case "eq3":
      return {
        id,
        type: "eq3",
        enabled: true,
        lowFreq: 200,
        lowGainDb: 0,
        midFreq: 1000,
        midQ: 1,
        midGainDb: 0,
        highFreq: 5000,
        highGainDb: 0
      } satisfies TrackEq3Effect;
    case "filter":
      return {
        id,
        type: "filter",
        enabled: true,
        mode: "lowpass",
        frequency: 1000,
        q: 1
      } satisfies TrackFilterEffect;
    case "compressor":
      return {
        id,
        type: "compressor",
        enabled: true,
        thresholdDb: -24,
        ratio: 4,
        attackMs: 3,
        releaseMs: 250,
        kneeDb: 30
      } satisfies TrackCompressorEffect;
    case "colorCorrection":
      return {
        id,
        type: "colorCorrection",
        enabled: true,
        brightness: 0,
        contrast: 1,
        saturation: 1,
        hue: 0,
        temperature: 0,
        tint: 0,
        shadows: 0,
        highlights: 0
      } satisfies TrackColorCorrectionEffect;
    case "videoBlur":
      return {
        id,
        type: "videoBlur",
        enabled: true,
        radius: 4
      } satisfies TrackVideoBlurEffect;
    case "sharpen":
      return {
        id,
        type: "sharpen",
        enabled: true,
        amount: 0.5,
        threshold: 0
      } satisfies TrackSharpenEffect;
    case "vignette":
      return {
        id,
        type: "vignette",
        enabled: true,
        intensity: 0.4,
        radius: 0.9,
        softness: 0.5
      } satisfies TrackVignetteEffect;
    case "chromaKey":
      return {
        id,
        type: "chromaKey",
        enabled: true,
        keyColor: "#00ff00",
        tolerance: 0.2,
        softness: 0.1,
        spill: 0.5
      } satisfies TrackChromaKeyEffect;
  }
}

/**
 * Create a minimal {@link TimelineClip} with defaults applied.
 *
 * Defaults:
 * - `id`: new UUID
 * - `startMs`: 0
 * - `durationMs`: 0
 * - `mediaType`: "video"
 * - `sourceType`: "generated"
 * - `status`: "draft"
 * - `locked`: false
 * - `versions`: []
 */
export function makeClip(overrides: Partial<TimelineClip> = {}): TimelineClip {
  return {
    id: createTimeOrderedUuid(),
    trackId: "",
    name: "",
    startMs: 0,
    durationMs: 0,
    mediaType: "video",
    sourceType: "generated",
    status: "draft",
    locked: false,
    versions: [],
    ...overrides
  };
}

/**
 * Create a minimal {@link TimelineSequence} with defaults applied.
 *
 * Defaults:
 * - `id`: new UUID
 * - `fps`: 30
 * - `width`: 1920
 * - `height`: 1080
 * - `durationMs`: 0
 * - `tracks`: []
 * - `clips`: []
 * - `markers`: []
 * - `createdAt` / `updatedAt`: current ISO timestamp
 */
export function makeSequence(
  overrides: Partial<TimelineSequence> = {}
): TimelineSequence {
  const now = nowIso();
  return {
    id: createTimeOrderedUuid(),
    projectId: "",
    name: "",
    fps: 30,
    width: 1920,
    height: 1080,
    durationMs: 0,
    tracks: [],
    clips: [],
    markers: [],
    createdAt: now,
    updatedAt: now,
    ...overrides
  };
}
